import argparse
import cmd
import os
# import readline
import sys
import time
import traceback
from datetime import datetime
from functools import wraps

import zmq

from rtSque import zmqports
from rtSque.loggers import ZmqPublisher
from rtSque.tinyrpc.rpc_client import RPCClientWrapper
from rtSque.tinyrpc.protocols.jsonrpc import RPCError
from rtSque.sequencer.sequencer import DEFAULT_MAIN_SEQ

# readline.parse_and_bind("bind ^I rl_complete")


def handle_response(afunc):

    @wraps(afunc)
    def _(*args, **kwargs):
        try:
            reply = afunc(*args, **kwargs)
            if reply:
                if hasattr(reply, 'result'):
                    print (reply.result)
                else:
                    print (str(reply))
        except RPCError as e:
            print (e.args[0], os.linesep, traceback.format_exc())

    return _


class SequencerDebugger(cmd.Cmd):
    prompt = 'sdb>'
    intro = 'Sequencer RPC client debugger'
    sequencer = None
    break_points = {}
    this_run = None
    stat = ''

    def do_EOF(self, line):
        """Ctrl-D to quit sdb without stopping the sequencer server"""
        return True

    @handle_response
    def do_load(self, sequence_db, sub_seq='all'):
        """
        Usage: load [sequence_db_name]
        load a sequencer database. Default loads a randomly generated database
        """
        if not sequence_db:
            return 'you must specify a sequence database name'
        rep = self.sequencer.load(sequence_db, sub_seq)
        if hasattr(rep, 'result'):
            return rep.result
        elif hasattr(rep, 'error'):
            return rep.error
        else:
            return None

    @handle_response
    def do_abort(self, line, sub_seq='all'):
        """abort the current running sequence"""
        reply = self.sequencer.abort(sub_seq)
        if hasattr(reply, 'result'):
            return reply.result
        elif hasattr(reply, 'error'):
            return reply.error

    # @handle_response
    def do_run(self, line, sub_seq='all'):
        """run the whole sequence without regard for any breakpoint"""
        res = self.sequencer.run(sub_site=sub_seq)
        print(res.result)

    def _show_sequence_item(self, item, pc):
        line_no = int(item[0])
        if line_no == pc+1:
            sys.stdout.write('-> ')
        else:
            sys.stdout.write('   ')
        test = eval(item[1])
        sys.stdout.write(str(item[0]) + ': ')
        sys.stdout.write('%s  | %s | %s | %s' % (test['GROUP'], test['TID'], test['FUNCTION'], test['DESCRIPTION']))
        if 'PARAM1' in test:
            sys.stdout.write(' | ' + test['PARAM1'])
        sys.stdout.write(os.linesep)
        if 'PARAM2' in test:
            sys.stdout.write(' | ' + test['PARAM2'])
        sys.stdout.write(
            ' | %s | %s | %s | %s | %s ' %
            (test['UNIT'], test['LOW'], test['HIGH'], test['KEY'], test['VAL'])
        )
        sys.stdout.write(os.linesep)

    @handle_response
    def do_list(self, lines, sub_seq=DEFAULT_MAIN_SEQ):
        """list [lines] around the current sequence item"""
        if len(lines) == 0:
            lines = '10'
        reply = self.sequencer.list(lines, sub_seq)
        pc, start, stop = reply.result[0]
        listings = reply.result[1:]
        for item in listings:
            self._show_sequence_item(item, pc)
        return

    @handle_response
    def do_break(self, line, sub_seq=DEFAULT_MAIN_SEQ):
        """set break point at [line]"""
        if line == '':
            line = '1'
        if not sub_seq in self.break_points.keys():
            self.break_points[sub_seq] = []
        self.break_points[sub_seq].append(int(line))

    def do_all(self, line):
        """show all the breakpoints"""
        for seq, b in self.break_points.items():
            print ('  {}-{}'.format(seq, str(b)))

    @handle_response
    def do_next(self, line, sub_seq=DEFAULT_MAIN_SEQ):
        """show the next line that will be executed"""
        return self.sequencer.next(sub_seq)

    @handle_response
    def do_skip(self, line, sub_seq=DEFAULT_MAIN_SEQ):
        """skip the right next test, equal to jump N+1"""
        reply = self.sequencer.skip(sub_seq)
        if reply:
            self._show_sequence_item(reply.result, -100)
        else:
            print ('skip failed')

    @handle_response
    def do_continue(self, line, sub_seq=DEFAULT_MAIN_SEQ):
        """continue execution from the current position,
        if you run continue, breakpoints are honored.
        If you use run, breakpoints are not honored"""
        reply = ' '
        if self.this_run is None:
            self.this_run = [b for b in self.break_points[sub_seq]]

        while reply is not None:
            next_p = self.sequencer.next(sub_seq)
            if next_p in self.this_run:
                sys.stdout.write('BREAK: ')
                self.do_list('1')
                self.this_run.remove(next_p)
                return
            reply = self.step_op(sub_seq)

        # we reached the end of the run
        self.this_run = None

    @handle_response
    def do_jump(self, dest, sub_seq=DEFAULT_MAIN_SEQ):
        """jump to the destination. Destination can be line number, group name or TID"""
        reply = self.sequencer.jump(dest, sub_seq)
        if hasattr(reply, 'result'):
            self._show_sequence_item(reply.result, -100)
        elif hasattr(reply, 'error'):
            print (reply.error)

    @handle_response
    def do_print(self, var_name, sub_seq=DEFAULT_MAIN_SEQ):
        """show the value of [var_name]"""
        ret = self.sequencer.show(var_name, sub_seq)
        if hasattr(ret, 'result'):
            return ret.result
        elif hasattr(ret, 'error'):
            return ret.error
        else:
            return None

    # @handle_response
    def do_status(self, line, sub_seq=DEFAULT_MAIN_SEQ):
        """return the current running status of the sequence"""
        self.stat = self.sequencer.status(sub_seq)
        return self.stat

    @handle_response
    def do_s(self, line, sub_seq=DEFAULT_MAIN_SEQ):
        """short name for step"""
        self.do_step(None, sub_seq)

    def step_op(self, sub_seq):
        self.do_list('1')
        t1 = datetime.now()
        reply = self.sequencer.step(sub_seq)
        if reply is None:
            print ('reached the end of sequence')
        else:
            t2 = datetime.now()
            print ('execution time: ' + str((t2-t1).total_seconds()) + ' seconds')
        return reply

    @handle_response
    def do_step(self, line, sub_seq=DEFAULT_MAIN_SEQ):
        """execute the current line, move PC to the next line"""
        self.step_op(sub_seq)

    @handle_response
    def do_wait(self, timeout, sub_seq=DEFAULT_MAIN_SEQ):
        """wait [timeout] seconds for the test sequence to finish"""
        if timeout == '':
            timeout = '0'
        return self.sequencer.wait(timeout=int(timeout),sub_site=sub_seq)

    @handle_response
    def do_loop(self, count):
        """wait [timeout] seconds for the test sequence to finish"""
        if count == '':
            count = '1'
        count = int(count)
        for i in range(count):
            self.do_run(None)
            start = time.time()
            time.sleep(3)
            while True:
                self.do_status(None)
                print ('Loop {0} of {1} running, time elapsed={2}s'.format(i+1, count, int(time.time()-start)))
                if self.stat.result == 'READY':
                    print ('loop {0} of {1} finished'.format(i+1, count))
                    break
                time.sleep(5)

    def do_quit(self, line):
        """quit sdb and stop the sequencer server. If you just want to quit sdb without stopping
        the sequencer server you should use ctrl-D"""
        self.sequencer.__getattr__('::stop::')()
        return True

    def emptyline(self):
        pass


def create_sdb(url, site):
    sdb = SequencerDebugger()
    if 'tcp' in url:
    	bind_url = 'tcp://*'
    else:
    	bind_url = url
    sequencer = RPCClientWrapper(url + ":" + str(zmqports.SEQUENCER_PORT + site),
                                  ZmqPublisher(zmq.Context(), bind_url + ":" + str(zmqports.SEQUENCER_PROXY_PUB + site),
                                  "Sequencer Proxy")
                                  ).remote_server()
    sdb.sequencer = sequencer
    return sdb

if __name__ == '__main__':
    parser = argparse.ArgumentParser()
    
    parser.add_argument('-u', '--url', help='Sequencer URL', default="tcp://127.0.0.1")
    # parser.add_argument('-u', '--url', help='Sequencer URL', default="ipc:///tmp/.localhost")
    parser.add_argument('-s', '--site', help='the site of the sequencer to connect to', type=int, default=0)
    parser.add_argument('-p', '--testplan', help='the test plan to load', default=None)
    args = parser.parse_args()

    sdb = create_sdb(args.url, args.site)

    if args.testplan:
        sdb.do_load(args.testplan)

    sdb.cmdloop()
